"""Library management system with Book and Library classes."""
from datetime import date, timedelta
from typing import Dict, List, Optional, Tuple


MAX_CHECKOUTS_PER_MEMBER = 3
OVERDUE_DAYS = 14


class Book:
    """Represents a book in the library."""

    def __init__(self, title: str, author: str, isbn: str, copies: int = 1):
        if not title or not title.strip():
            raise ValueError("Title cannot be empty")
        if not author or not author.strip():
            raise ValueError("Author cannot be empty")
        if not isbn or not isbn.strip():
            raise ValueError("ISBN cannot be empty")
        if copies < 1:
            raise ValueError("Copies must be at least 1")
        self.title = title.strip()
        self.author = author.strip()
        self.isbn = isbn.strip()
        self.total_copies = copies
        self.available_copies = copies

    def checkout(self) -> None:
        """Check out one copy. Raises ValueError if none available."""
        if self.available_copies <= 0:
            raise ValueError(f"No copies available for '{self.title}'")
        self.available_copies -= 1

    def return_book(self) -> None:
        """Return one copy. Raises ValueError if all copies already returned."""
        if self.available_copies >= self.total_copies:
            raise ValueError(f"All copies of '{self.title}' are already returned")
        self.available_copies += 1

    @property
    def is_available(self) -> bool:
        """True if at least one copy is available."""
        return self.available_copies > 0

    def __repr__(self) -> str:
        return f"Book('{self.title}' by {self.author})"


class Library:
    """Manages a collection of books and member checkouts."""

    def __init__(self):
        self._books: Dict[str, Book] = {}  # isbn -> Book
        self._checkouts: Dict[str, List[Tuple[str, date]]] = {}  # member_id -> [(isbn, checkout_date)]

    def add_book(self, book: Book) -> None:
        """Add a book to the library. Raises ValueError on duplicate ISBN."""
        if book.isbn in self._books:
            raise ValueError(f"Book with ISBN '{book.isbn}' already exists")
        self._books[book.isbn] = book

    def remove_book(self, isbn: str) -> Book:
        """Remove and return a book by ISBN. Raises KeyError if not found."""
        if isbn not in self._books:
            raise KeyError(f"No book with ISBN '{isbn}'")
        return self._books.pop(isbn)

    def get_book(self, isbn: str) -> Optional[Book]:
        """Get a book by ISBN, or None if not found."""
        return self._books.get(isbn)

    def search(self, query: str) -> List[Book]:
        """Search books by title or author (case-insensitive substring match).

        Returns matching books sorted by title (case-insensitive).
        """
        if not query or not query.strip():
            return []
        q = query.strip().lower()
        results = [
            book for book in self._books.values()
            if q in book.title.lower() or q in book.author.lower()
        ]
        return sorted(results, key=lambda b: b.title.lower())

    def checkout_book(self, isbn: str, member_id: str, checkout_date: Optional[date] = None) -> None:
        """Check out a book to a member.

        Raises:
            KeyError: if ISBN not found
            ValueError: if member at max checkouts or book not available
        """
        if isbn not in self._books:
            raise KeyError(f"No book with ISBN '{isbn}'")

        member_books = self._checkouts.get(member_id, [])
        if len(member_books) >= MAX_CHECKOUTS_PER_MEMBER:
            raise ValueError(
                f"Member '{member_id}' has reached the maximum of "
                f"{MAX_CHECKOUTS_PER_MEMBER} checkouts"
            )

        book = self._books[isbn]
        book.checkout()  # raises ValueError if not available

        if checkout_date is None:
            checkout_date = date.today()

        if member_id not in self._checkouts:
            self._checkouts[member_id] = []
        self._checkouts[member_id].append((isbn, checkout_date))

    def return_book(self, isbn: str, member_id: str) -> None:
        """Return a book from a member.

        Raises:
            KeyError: if ISBN not found in library
            ValueError: if member doesn't have this book checked out
        """
        if isbn not in self._books:
            raise KeyError(f"No book with ISBN '{isbn}'")

        member_books = self._checkouts.get(member_id, [])
        checkout_entry = None
        for entry in member_books:
            if entry[0] == isbn:
                checkout_entry = entry
                break

        if checkout_entry is None:
            raise ValueError(
                f"Member '{member_id}' does not have book '{isbn}' checked out"
            )

        self._books[isbn].return_book()
        member_books.remove(checkout_entry)
        if not member_books:
            del self._checkouts[member_id]

    def get_member_books(self, member_id: str) -> List[str]:
        """Get list of ISBNs checked out by a member."""
        return [isbn for isbn, _ in self._checkouts.get(member_id, [])]

    def get_overdue_books(self, current_date: Optional[date] = None) -> List[Tuple[str, str, int]]:
        """Get list of overdue books as (isbn, member_id, days_overdue).

        A book is overdue if checked out for more than OVERDUE_DAYS days
        (strictly greater than, not equal to).

        Returns results sorted by days_overdue descending.
        """
        if current_date is None:
            current_date = date.today()

        overdue = []
        for member_id, books in self._checkouts.items():
            for isbn, checkout_date in books:
                days_out = (current_date - checkout_date).days
                if days_out > OVERDUE_DAYS:
                    overdue.append((isbn, member_id, days_out - OVERDUE_DAYS))

        return sorted(overdue, key=lambda x: x[2], reverse=True)

    def get_stats(self) -> dict:
        """Get library statistics.

        Returns dict with:
            total_books: total number of book copies across all titles
            available_books: number of available copies
            checked_out_books: number of checked out copies
            total_members: number of members with active checkouts
        """
        total = sum(b.total_copies for b in self._books.values())
        available = sum(b.available_copies for b in self._books.values())
        return {
            "total_books": total,
            "available_books": available,
            "checked_out_books": total - available,
            "total_members": len(self._checkouts),
        }
